# src/agent/loop.py
from dataclasses import dataclass, field
from typing import Any
import time
from src.agent.tools import ToolRegistry, ToolResult
from src.agent.safety import SafetyGuard, SafetyViolation
from src.models.gateway_client import GatewayClient

MAX_STEPS = 15
TIMEOUT_SECONDS = 120

@dataclass
class AgentState:
    task: str
    steps: list[dict] = field(default_factory=list)
    token_budget: int = 50_000
    tokens_used: int = 0
    started_at: float = field(default_factory=time.monotonic)

    @property
    def timed_out(self) -> bool:
        return time.monotonic() - self.started_at > TIMEOUT_SECONDS

    @property
    def budget_exhausted(self) -> bool:
        return self.tokens_used >= self.token_budget

class AgentBudgetExceeded(Exception): pass
class AgentMaxStepsExceeded(Exception): pass
class AgentTimeout(Exception): pass

async def run_agent(
    task: str,
    tools: ToolRegistry,
    client: GatewayClient,
    safety: SafetyGuard,
    token_budget: int = 50_000,
) -> dict:
    state = AgentState(task=task, token_budget=token_budget)
    messages = [
        {"role": "system", "content": build_system_prompt(tools)},
        {"role": "user", "content": task},
    ]

    for step_n in range(MAX_STEPS):
        if state.timed_out:
            raise AgentTimeout(f"Agent timed out after {TIMEOUT_SECONDS}s at step {step_n}")
        if state.budget_exhausted:
            raise AgentBudgetExceeded(f"Token budget {state.token_budget} exhausted at step {step_n}")

        response = await client.complete({
            "model": "gpt-4o",
            "messages": messages,
            "tools": tools.schemas(),
            "tool_choice": "auto",
            "max_tokens": 4096,
        })
        state.tokens_used += response.usage.total_tokens

        # Check for task completion (no tool call = final answer)
        if not response.tool_calls:
            return {"status": "completed", "answer": response.content,
                    "steps": step_n + 1, "tokens": state.tokens_used}

        # Process each tool call
        messages.append({"role": "assistant", "content": response.content,
                          "tool_calls": response.tool_calls})

        for tool_call in response.tool_calls:
            # Safety check before every tool call
            violation = safety.check(tool_call, state)
            if violation:
                raise SafetyViolation(f"Tool call blocked: {violation}")

            result: ToolResult = await tools.call(
                tool_call.function.name,
                tool_call.function.arguments,
            )
            messages.append({
                "role": "tool",
                "tool_call_id": tool_call.id,
                "content": result.content,
            })
            state.steps.append({
                "step": step_n, "tool": tool_call.function.name,
                "args": tool_call.function.arguments, "result_summary": result.summary,
            })

    raise AgentMaxStepsExceeded(f"Agent exceeded MAX_STEPS={MAX_STEPS}")

