import json
from dataclasses import dataclass
from typing import Callable, Any, Awaitable
import jsonschema

@dataclass
class ToolResult:
    content: str   # fed back to LLM
    summary: str   # for trace logs (may be truncated)
    raw: Any = None

class ToolNotAllowed(Exception): pass
class ToolArgumentError(Exception): pass

class ToolRegistry:
    def __init__(self):
        self._tools: dict[str, dict] = {}   # name → {fn, schema, description}

    def register(self, name: str, fn: Callable[..., Awaitable[ToolResult]],
                 schema: dict, description: str) -> None:
        self._tools[name] = {"fn": fn, "schema": schema, "description": description}

    def schemas(self) -> list[dict]:
        return [
            {
                "type": "function",
                "function": {
                    "name": name,
                    "description": spec["description"],
                    "parameters": spec["schema"],
                },
            }
            for name, spec in self._tools.items()
        ]

    async def call(self, name: str, arguments_json: str) -> ToolResult:
        if name not in self._tools:
            raise ToolNotAllowed(f"Tool '{name}' is not in the allowlist")
        spec = self._tools[name]
        try:
            args = json.loads(arguments_json)
        except json.JSONDecodeError as e:
            raise ToolArgumentError(f"Invalid JSON arguments for '{name}': {e}")
        try:
            jsonschema.validate(args, spec["schema"])
        except jsonschema.ValidationError as e:
            raise ToolArgumentError(f"Argument validation failed for '{name}': {e.message}")
        return await spec["fn"](**args)

