import asyncio, textwrap, traceback
from src.agent.tools import ToolResult

CODE_EXEC_SCHEMA = {
    "type": "object",
    "required": ["code"],
    "properties": {
        "code": {"type": "string", "maxLength": 10_000, "description": "Python code to execute"},
    },
    "additionalProperties": False,
}

EXEC_TIMEOUT = 30  # seconds

async def execute_python(code: str) -> ToolResult:
    """Run code in a subprocess with restricted permissions."""
    wrapped = textwrap.dedent(f"""
        import sys, io, contextlib
        _stdout = io.StringIO()
        _stderr = io.StringIO()
        try:
            with contextlib.redirect_stdout(_stdout), contextlib.redirect_stderr(_stderr):
                exec(compile({repr(code)}, '<agent>', 'exec'), {{'__builtins__': __builtins__}})
        except Exception as e:
            print(f'ERROR: {{type(e).__name__}}: {{e}}', file=_stderr)
        print(_stdout.getvalue(), end='')
        print(_stderr.getvalue(), end='', file=sys.stderr)
    """)
    try:
        proc = await asyncio.create_subprocess_exec(
            "python3", "-c", wrapped,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
        )
        stdout, stderr = await asyncio.wait_for(
            proc.communicate(), timeout=EXEC_TIMEOUT
        )
        output = stdout.decode()[:5000]  # cap output size
        error = stderr.decode()[:1000]
        if error:
            return ToolResult(content=f"Output:\n{output}\nErrors:\n{error}",
                              summary="Code executed with errors")
        return ToolResult(content=output or "(no output)", summary="Code executed successfully")
    except asyncio.TimeoutError:
        proc.kill()
        return ToolResult(content=f"ERROR: Code execution timed out after {EXEC_TIMEOUT}s",
                          summary="Timeout")

