import asyncio, uuid, httpx
from src.agent.tools import ToolResult

APPROVAL_SCHEMA = {
    "type": "object",
    "required": ["action_description", "consequence"],
    "properties": {
        "action_description": {"type": "string", "maxLength": 500},
        "consequence":        {"type": "string", "maxLength": 200},
        "approval_timeout_seconds": {"type": "integer", "default": 300, "maximum": 3600},
    },
    "additionalProperties": False,
}

async def request_human_approval(
    action_description: str,
    consequence: str,
    approval_timeout_seconds: int = 300,
    slack_webhook: str = "",
    approval_api: str = "",
) -> ToolResult:
    approval_id = str(uuid.uuid4())

    # Post to Slack
    await httpx.AsyncClient().post(slack_webhook, json={
        "text": (
            f":robot_face: *Agent approval request*\n"
            f"Action: {action_description}\n"
            f"Consequence: {consequence}\n"
            f"Approve: {approval_api}/approve/{approval_id}\n"
            f"Reject: {approval_api}/reject/{approval_id}\n"
            f"Expires in: {approval_timeout_seconds}s"
        )
    })

    # Poll for decision
    deadline = asyncio.get_event_loop().time() + approval_timeout_seconds
    while asyncio.get_event_loop().time() < deadline:
        resp = await httpx.AsyncClient().get(f"{approval_api}/status/{approval_id}")
        status = resp.json().get("status")
        if status == "approved":
            return ToolResult(content="APPROVED", summary="Human approved the action")
        if status == "rejected":
            reason = resp.json().get("reason", "No reason given")
            return ToolResult(content=f"REJECTED: {reason}",
                              summary="Human rejected the action")
        await asyncio.sleep(5)

    return ToolResult(content="TIMEOUT: No approval within window. Action not taken.",
                      summary="Approval timed out")

