from opentelemetry import trace
from opentelemetry.trace import Span
import json

tracer = trace.get_tracer("agent-workflow")

def trace_agent_run(task: str, run_id: str):
    return tracer.start_as_current_span(
        "agent.run",
        attributes={"agent.task": task[:200], "agent.run_id": run_id},
    )

def trace_tool_call(tool_name: str, arguments: str, result_summary: str) -> None:
    span: Span = trace.get_current_span()
    span.add_event("tool_call", {
        "tool.name": tool_name,
        "tool.arguments": arguments[:500],
        "tool.result_summary": result_summary[:200],
    })

def trace_agent_complete(steps: int, tokens: int, status: str) -> None:
    span: Span = trace.get_current_span()
    span.set_attributes({
        "agent.steps_taken": steps,
        "agent.tokens_used": tokens,
        "agent.status": status,
    })
